interface DownloadLink {
  icon: React.ReactNode
  href: string
  ariaLabel: string
}

const links: DownloadLink[] = [
  {
    icon: <GooglePlayStore />,
    href: STORE_URLS.playStore,
    ariaLabel: 'Download Living Seed on Google Play',
  },
  {
    icon: <AppleAppStore />,
    href: STORE_URLS.appStore,
    ariaLabel: 'Download Living Seed on the App Store',
  },
]

/// Pair of black pill-shaped CTAs that link to the mobile app on the
/// Play Store and App Store. Adapted from the divest-website's
/// `AppDownload` component but using lucide / inline SVG icons so we
/// don't need to ship raster assets, and using the bookstore's design
/// tokens (rounded-full, dark surface, white text).
const AppDownload = () => (
  <div className="flex w-full grid-cols-2 justify-evenly md:grid md:w-fit md:gap-x-4">
    {links.map((link, index) => (
      <a
        href={link.href}
        target="_blank"
        rel="noopener noreferrer"
        aria-label={link.ariaLabel}
        className="w-full cursor-pointer"
        key={index}
      >
        <span>{link.icon}</span>
      </a>
    ))}
  </div>
)

export default AppDownload
